    margin: 0;
    font-size: 1.1rem;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-info {
    flex: 1;
    margin-right: 1rem;
    word-break: break-all;
}

.error-message {
    color: #dc3545;
    font-weight: 500;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.75rem;
    cursor: pointer;
    white-space: nowrap;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

