namespace sv_6e9f90363a4c4a10a6d42523c145098d.Components;

public record FileInfo(string Name, long Size, string Type);

public partial class FileDropZone : IAsyncDisposable
{
    private const long MaxFileSizeBytes = 10L * 1024 * 1024;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _instance;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;

    private readonly List<FileEntry> _files = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-6e9f90363a4c4a10a6d42523c145098d/Components/FileDropZone.razor.js");
            _instance = await _module.InvokeAsync<IJSObjectReference>("init", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnFilesDropped(DroppedFileDto[] files)
    {
        foreach (var f in files)
        {
            var info = new FileInfo(f.Name, f.Size, f.Type);
            _files.Add(new FileEntry(info, f.Size > MaxFileSizeBytes));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(e => !e.IsOversize)
            .Select(e => e.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_instance is not null)
        {
            await _instance.InvokeVoidAsync("dispose");
            await _instance.DisposeAsync();
        }
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    public record FileEntry(FileInfo Info, bool IsOversize);

